CREATE OR REPLACE FUNCTION to_tdatetime (adt_date timestamp(0),as_format_date text default null,as_format_time text default null) RETURNS varchar AS $body$
BEGIN
  --return  trim(to_char(adt_date,'dd-mm-'))||substr(trim(to_char(li_year + 543)),3,2)||' '||trim(To_char(adt_date,ls_format_time));
  if coalesce(adt_date::text, '') = '' then
    return regexp_replace(regexp_replace(coalesce(as_format_date,'dd-mm-yy')||' '||coalesce(as_format_time,'HH24:MI:SS'),'\d',null, 'g'),'\w','#', 'g');
  else
    return to_char(adt_date,coalesce(as_format_date,'dd-mm-yy')||' '||coalesce(as_format_time,'HH24:MI:SS'), 'NLS_CALENDAR=''THAI BUDDHA'' NLS_DATE_LANGUAGE=THAI');
  end if;
exception WHEN OTHERS then CALL spa_dberror('to_tdatetime');return ' ';

end;
$body$
